--
-- Table structure for table `password_reset_tokens`
--

CREATE TABLE `password_reset_tokens` (
  `email` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `token` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Table structure for table `pemeriksaan_bayi`
--

CREATE TABLE `pemeriksaan_bayi` (
  `id` bigint UNSIGNED NOT NULL,
  `pasien_id` bigint UNSIGNED NOT NULL,
  `tgl_periksa` date NOT NULL,
  `keterangan_umur` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `usia_bulan` int DEFAULT NULL,
  `berat_badan` decimal(5,2) DEFAULT NULL,
  `tinggi_badan` decimal(5,2) DEFAULT NULL,
  `cara_ukur` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'terlentang / berdiri',
  `lila` decimal(5,2) DEFAULT NULL,
  `lingkar_kepala` decimal(5,2) DEFAULT NULL,
  `status_gizi` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'BB/U',
  `status_stunting` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'TB/U',
  `status_bbtb` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'BB/TB',
  `zscore_bbu` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `zscore_tbu` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `zscore_bbtb` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `kenaikan_bb` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Status kenaikan berat badan (naik / tidak naik)',
  `keterangan_bb` varchar(150) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Keterangan detail kenaikan BB berdasarkan buku KIA',
  `pitting_edema` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'tidak ada' COMMENT 'Tingkatan klinis pitting edema bilateral anak',
  `vitamin_a` tinyint(1) NOT NULL DEFAULT '0',
  `obat_cacing` tinyint(1) NOT NULL DEFAULT '0',
  `jenis_imunisasi` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `asi_eksklusif` tinyint(1) NOT NULL DEFAULT '0',
  `pmba` tinyint(1) NOT NULL DEFAULT '0',
  `sdidtk` tinyint(1) NOT NULL DEFAULT '0',
  `rambu_gizi` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `titik_pertumbuhan` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `deteksi_tbc` tinyint(1) NOT NULL DEFAULT '0',
  `kie` tinyint(1) NOT NULL DEFAULT '0',
  `rujuk` tinyint(1) NOT NULL DEFAULT '0',
  `kelas_ibu` tinyint(1) NOT NULL DEFAULT '0',
  `menerima_mbg` tinyint(1) NOT NULL DEFAULT '0',
  `catatan` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

